def gen(rng, size):
    n = rng.randrange(1, max(2, size) + 1)
    if rng.random() < 0.5:
        avg = rng.randrange(0, 50)
        arr = [avg] * n
        for _ in range(rng.randrange(0, n * 2)):
            i = rng.randrange(n); j = rng.randrange(n)
            if arr[i] > 0:
                arr[i] -= 1; arr[j] += 1
        return [arr]
    return [[rng.randrange(0, 100) for _ in range(n)]]

