var findMinMoves = function(machines) {
    const n = machines.length;
    const s = machines.reduce((a, b) => a + b, 0);
    if (s % n !== 0) return -1;
    const avg = s / n;
    let prefix = 0, res = 0;
    for (const m of machines) {
        const d = m - avg;
        prefix += d;
        res = Math.max(res, d, Math.abs(prefix));
    }
    return res;
};
